import{_ as e,o as n,c as s,a2 as i}from"./chunks/framework.LN3EJxkW.js";const k=JSON.parse('{"title":"Tokenization、Context Window 与输入输出成本","description":"","frontmatter":{"type":"ai-note","stage":"beginner","topic":"tokenization-context-cost","verified":"2026-07-17T00:00:00.000Z","tags":["ai","tokenization","context-window","cost"]},"headers":[],"relativePath":"04-ai/notes/foundations/tokenization-context-cost.md","filePath":"04-ai/notes/foundations/tokenization-context-cost.md","lastUpdated":1784249568000}'),t={name:"04-ai/notes/foundations/tokenization-context-cost.md"};function l(o,a,r,p,h,d){return n(),s("div",null,[...a[0]||(a[0]=[i(`<h1 id="tokenization、context-window-与输入输出成本" tabindex="-1">Tokenization、Context Window 与输入输出成本 <a class="header-anchor" href="#tokenization、context-window-与输入输出成本" aria-label="Permalink to &quot;Tokenization、Context Window 与输入输出成本&quot;">​</a></h1><h2 id="_1-概念、用途与工程边界" tabindex="-1">1. 概念、用途与工程边界 <a class="header-anchor" href="#_1-概念、用途与工程边界" aria-label="Permalink to &quot;1. 概念、用途与工程边界&quot;">​</a></h2><h3 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h3><p>Tokenization 把文本或其他输入转换为模型处理的离散 Token ID。Token 可能是字、子词、标点、空格片段或字节组合，不等于字符或单词。Context Window 是一次推理能处理的 Token 总范围，通常包括系统指令、消息历史、工具定义、检索内容、当前输入和已生成内容。输入输出成本是供应商根据各类 Token 或模态用量计算的费用。</p><h3 id="为什么需要" tabindex="-1">为什么需要 <a class="header-anchor" href="#为什么需要" aria-label="Permalink to &quot;为什么需要&quot;">​</a></h3><p>Token 数影响请求能否进入上下文、推理延迟和费用。字符数相同的不同语言、空白、代码和编码可能产生不同 Token 数。上下文过长还可能降低关键信息被正确使用的概率。</p><h3 id="核心特性" tabindex="-1">核心特性 <a class="header-anchor" href="#核心特性" aria-label="Permalink to &quot;核心特性&quot;">​</a></h3><ul><li>Tokenizer 属于具体模型或模型族；不能用一个模型的 Token 估算器精确计算另一个模型。</li><li>上下文上限不是全部可用于输入，输出预算也占用容量，具体规则以 API 为准。</li><li>工具 Schema、图片、音频、缓存 Token 和推理 Token可能有独立统计或计费方式。</li><li>Prompt caching 可降低重复前缀的成本或延迟，但有命中条件、保留策略和隐私边界。</li><li>截断策略可能直接报错，也可能删除早期内容；自动截断必须显式理解。</li></ul><h3 id="工程使用" tabindex="-1">工程使用 <a class="header-anchor" href="#工程使用" aria-label="Permalink to &quot;工程使用&quot;">​</a></h3><p>建立 Token Budget：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>系统/安全规则：固定上限</span></span>
<span class="line"><span>工具定义：按任务选择，不全量注入</span></span>
<span class="line"><span>历史：保留关键事实，旧内容摘要</span></span>
<span class="line"><span>检索：按相关性、权限和新鲜度筛选</span></span>
<span class="line"><span>当前输入：完整保留或先明确拒绝过长输入</span></span>
<span class="line"><span>输出：为任务设置最大值</span></span>
<span class="line"><span>安全余量：处理估算误差和协议开销</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>在请求前使用官方 Tokenizer 或供应商计数接口估算；响应后以 API Usage 为准。日志按组成部分记录 Token，才能定位增长来源。</p><h3 id="常见错误与边界" tabindex="-1">常见错误与边界 <a class="header-anchor" href="#常见错误与边界" aria-label="Permalink to &quot;常见错误与边界&quot;">​</a></h3><ul><li>使用“一个 Token 约等于几个字”的经验值做硬限制。</li><li>每轮把全部历史、全部文档和全部工具重复发送。</li><li>只限制输入，不限制最大输出和 Agent 总步骤。</li><li>达到上限时直接从最早消息删除，丢失安全约束、用户决策或任务状态。</li><li>以为更长上下文必然提高质量，没有用评测集比较相关性和干扰。</li></ul><h3 id="延伸机制" tabindex="-1">延伸机制 <a class="header-anchor" href="#延伸机制" aria-label="Permalink to &quot;延伸机制&quot;">​</a></h3><p>上下文管理应同时考虑权限、来源可信度、冲突和时间有效性。压缩与摘要会损失信息，重要事实应以结构化状态或数据库事实保存，而不是仅依赖对话摘要。</p><h2 id="context-budget-的组成" tabindex="-1">Context Budget 的组成 <a class="header-anchor" href="#context-budget-的组成" aria-label="Permalink to &quot;Context Budget 的组成&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[&quot;指令&quot;] --&gt; G[&quot;上下文窗口&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B[&quot;当前输入&quot;] --&gt; G</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C[&quot;历史与状态&quot;] --&gt; G</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D[&quot;工具定义&quot;] --&gt; G</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E[&quot;检索内容&quot;] --&gt; G</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F[&quot;输出与推理预算&quot;] --&gt; G</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G --&gt; H[&quot;Usage 与费用&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>窗口计算规则、缓存计量和推理 Token 是模型与 API 特定行为。不能把某供应商或某模型的字段、比例和最大值写成跨供应商规则。</p><h2 id="计量项明细" tabindex="-1">计量项明细 <a class="header-anchor" href="#计量项明细" aria-label="Permalink to &quot;计量项明细&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>请求前</th><th>请求后</th><th>边界</th></tr></thead><tbody><tr><td>输入 Token</td><td>用对应模型 Tokenizer/计数接口估算</td><td>以 Usage 为准</td><td>工具 Schema 和多模态也可能计入</td></tr><tr><td>缓存 Token</td><td>判断前缀和供应商命中条件</td><td>读取 Usage 明细</td><td>缓存不等于应用数据持久化策略</td></tr><tr><td>输出 Token</td><td>设置任务上限</td><td>读取可见与其他明细</td><td>达上限可能得到不完整结果</td></tr><tr><td>费用</td><td>按最坏情况预留</td><td>结合价格版本结算</td><td>图片、音频、工具可能另计</td></tr></tbody></table><h2 id="可计算示例" tabindex="-1">可计算示例 <a class="header-anchor" href="#可计算示例" aria-label="Permalink to &quot;可计算示例&quot;">​</a></h2><p>若某模型窗口为 16,000 Token，指令 800、工具 1,200、历史 4,000、检索 6,000、当前输入 1,000，并为输出预留 2,000，则总预算为 15,000，余量 1,000。若再加入 1,500 Token 文档，请求将超过窗口；应减少检索或历史，而不是静默删除安全指令。</p><h2 id="验证与排错" tabindex="-1">验证与排错 <a class="header-anchor" href="#验证与排错" aria-label="Permalink to &quot;验证与排错&quot;">​</a></h2><ol><li>记录各上下文组成部分的估算值，而非只有总数。</li><li>请求后比较估算与 Usage，超过容差时检查 Tokenizer、协议开销和模型版本。</li><li>测试达到 <code>max_output_tokens</code> 时的完成状态与 <code>incomplete_details</code>。</li><li>Context 错误时检查自动截断设置；OpenAI Responses 的 <code>truncation</code> 默认 <code>disabled</code>，超窗会以 400 失败，<code>auto</code> 才会从会话开头丢弃输入项。</li></ol><h2 id="练习与完成标准" tabindex="-1">练习与完成标准 <a class="header-anchor" href="#练习与完成标准" aria-label="Permalink to &quot;练习与完成标准&quot;">​</a></h2><p>为一个带 4 个工具和 RAG 的任务制作 Token Budget。验收：分开统计指令、工具、历史、检索、当前输入和输出；保留安全余量；超限时有确定裁剪优先级；不删除授权规则；用实际 Usage 校准估算。</p><h2 id="完整案例-rag-问答的-context-预算" tabindex="-1">完整案例：RAG 问答的 Context 预算 <a class="header-anchor" href="#完整案例-rag-问答的-context-预算" aria-label="Permalink to &quot;完整案例：RAG 问答的 Context 预算&quot;">​</a></h2><h3 id="输入" tabindex="-1">输入 <a class="header-anchor" href="#输入" aria-label="Permalink to &quot;输入&quot;">​</a></h3><ul><li>模型窗口为 32,000 Token；该数值只对指定模型版本有效。</li><li>指令 1,200，工具定义 2,800，当前问题估算 500。</li><li>历史最多 6,000，检索候选最多 12,000，输出上限 4,000，安全余量 2,000。</li></ul><h3 id="逐步处理" tabindex="-1">逐步处理 <a class="header-anchor" href="#逐步处理" aria-label="Permalink to &quot;逐步处理&quot;">​</a></h3><ol><li>使用对应模型的计数工具估算每个组成部分，不以字符数比例替代。</li><li>固定保留安全与授权指令、当前问题和输出预算。</li><li>工具只注入当前任务可能使用的集合；历史提取结构化状态后按相关性裁剪。</li><li>检索候选按权限、来源、新鲜度和相关性选择，保留段落边界与引用。</li><li>请求前计算 <code>1200+2800+500+6000+12000+4000+2000=28500</code>，低于 32,000。</li><li>响应后读取实际 Usage，按输入、缓存、输出和供应商提供的其他明细校准估算。</li></ol><h3 id="输出" tabindex="-1">输出 <a class="header-anchor" href="#输出" aria-label="Permalink to &quot;输出&quot;">​</a></h3><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;window&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">32000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;estimated_total&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">28500</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;headroom&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3500</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;max_output_tokens&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">4000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;truncation_policy&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;reject_then_rebuild_context&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><ul><li>分别构造 31,999、32,000 和超上限请求，观察具体 API 行为。</li><li>强制达到输出上限，确认应用识别 <code>incomplete</code>，不解析半截结构。</li><li>对估算与实际 Usage 计算误差并按模型版本监控。</li><li>删除历史时保留用户确认、权限和任务状态到受控结构化存储。</li></ul><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>若检索新增 8,000 Token，不能简单从开头截断整个输入。应先减少低相关候选，再压缩非关键历史，必要时拒绝并提示拆分任务。OpenAI Responses 使用 <code>truncation: &quot;auto&quot;</code> 会从会话开头丢弃输入项；是否启用必须是显式产品选择。</p><h2 id="边界检查矩阵" tabindex="-1">边界检查矩阵 <a class="header-anchor" href="#边界检查矩阵" aria-label="Permalink to &quot;边界检查矩阵&quot;">​</a></h2><ol><li>Tokenizer 必须与目标模型或官方计数接口匹配。</li><li>输入预算包含指令、历史、工具 Schema、检索和当前输入。</li><li>输出上限可能同时覆盖可见输出与推理 Token，依模型接口而定。</li><li>图片和音频使用独立计量规则，不能按文本字符估算。</li><li>缓存命中条件和保留策略是供应商特定行为。</li><li>截断前识别不可删除的安全、授权与用户决策。</li><li>历史摘要保存来源和版本，避免把推断升级为事实。</li><li>检索上下文先按权限过滤，再按相关性和新鲜度选择。</li><li>达到输出上限时结构化 JSON 可能不完整。</li><li>实际 Usage 是结算依据，估算只用于调用前控制。</li><li>价格表变化需保存价格日期和币种。</li><li>更长窗口是否改善质量必须通过固定评测验证。</li></ol><h2 id="输出预算与不完整状态" tabindex="-1">输出预算与不完整状态 <a class="header-anchor" href="#输出预算与不完整状态" aria-label="Permalink to &quot;输出预算与不完整状态&quot;">​</a></h2><p>输出上限是资源边界，不是希望模型“尽量简短”的语气要求。达到上限时，文本可能在句中结束，JSON 可能缺少闭合符号，Tool 参数也可能不完整。应用必须先检查供应商完成状态，再解析结构；不能因为已经收到部分文本就标记成功。对于 OpenAI Responses，<code>max_output_tokens</code> 是请求字段，覆盖可见输出与推理 Token 的上限；响应为 <code>incomplete</code> 时读取 <code>incomplete_details</code> 判断原因。</p><p>减少上下文时应维护一份优先级：服务端授权事实与当前任务状态来自受控存储；安全约束和当前用户输入优先保留；旧对话可转换为带来源的结构化摘要；低相关检索片段先删除。摘要仍是派生数据，必须记录生成版本并允许回到原始授权记录核对。</p><p>成本分析需要把“每次请求平均费用”和“完成一次用户任务的费用”分开。缩短单次请求但引发更多重试、Tool 循环或人工接管，任务总成本可能上升。评测表应同时记录成功率、总调用数、输入输出 Usage、延迟和最终完成状态。</p><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://huggingface.co/learn/llm-course/en/chapter2/4" target="_blank" rel="noreferrer">Hugging Face LLM Course：Tokenizers</a>（访问日期：2026-07-17）</li><li><a href="https://developers.google.com/machine-learning/resources/intro-llms" target="_blank" rel="noreferrer">Google ML：Introduction to Large Language Models</a>（访问日期：2026-07-17）</li><li><a href="https://platform.openai.com/docs/api-reference/responses" target="_blank" rel="noreferrer">OpenAI API：Responses Usage</a>（访问日期：2026-07-17）</li><li><a href="https://docs.anthropic.com/en/docs/build-with-claude/token-counting" target="_blank" rel="noreferrer">Anthropic Docs：Token Counting</a>（访问日期：2026-07-17）</li></ul>`,46)])])}const u=e(t,[["render",l]]);export{k as __pageData,u as default};
